import React, { useState } from 'react'
import Head from 'next/head'
import Link from 'next/link'
import fetch from 'isomorphic-unfetch'

const Home = ({ data }) => {
  // const week = Object.values(data[`week-1`])
  const week = {
    "label": "Week 1",
    "monday": {
      "label":"Mon",
      "exercise":"Rest",
      "tag":"rest"
    },
    "tuesday": {
      "label":"Tue",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "wednesday": {
      "label":"Wed",
      "exercise":"2 mi run or cross",
      "tag":"run/cross"
    },
    "thursday": {
      "label":"Thu",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "friday": {
      "label":"Fri",
      "exercise":"Rest",
      "tag":"rest"
    },
    "saturday": {
      "label":"Sat",
      "exercise":"30 min cross",
      "tag":"cross"
    },
    "sunday": {
      "label":"Sun",
      "exercise":"4 mi run",
      "tag":"run"
    }
  }

  return(
    <div className="container">

      <Head>
        <title>{week.label}</title>
        <link rel="icon" href="" />
      </Head>

      <div className="week-header">
        <h1>{week.label}</h1>
      </div>


      {
       Object.values(week).map((foo, i) => (
          <div key={i}>
            <h1>{foo.label}</h1>
            <p>{foo.exercise}</p>
          </div>
        ))
      }

      <style jsx>{`
        body{
          margin: 0;
          padding: 0;
        }

        .container{
          height: 100vh;
          width: 100%;
          display: flex;
          flex-flow: column;
          justify-content: center;
          align-items: center;
          font-family: sans-serif;
        }

        .week-header{
          font-size: 4rem;
          margin: 0;
          padding: 0;
          display: grid;
          grid-template-columns: 1fr 1fr;
        }



      `}
      </style>

    </div>
  )
}

// Home.getInitialProps = async () => {
//   const res = await fetch('http://localhost:3000/api/daily')
//   const json = await res.json()

//   return { data: json }
// }

export default Home
